export const 陳安世符一 = (bi) => {
    const u = bi.u;
    const k = 1.05;
    const X = (c) => (c - 11.75) * k;
    const Z = (r) => (r - 1.4) * k;
    const 線 = (書, 寬 = 0.6) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.6) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    bi.硃(() => {
        // 頂艹：寬弧貫雙莖
        線(p => p.M(X(6.9), Z(3.3)).C(X(9.5), Z(4.1), X(13.5), Z(3.9), X(16.6), Z(2.9)), 0.65);
        線(p => p.M(X(9.0), Z(2.3)).L(X(8.95), Z(5.2)));
        線(p => p.M(X(13.9), Z(2.2)).L(X(13.85), Z(5.3)));
        // 曲箱雙室
        線(p => p.M(X(7.6), Z(5.4)).L(X(7.6), Z(8.6))); // 左脅
        線(p => p.M(X(7.6), Z(5.45)).L(X(15.9), Z(5.2))
            .C(X(16.5), Z(5.2), X(16.6), Z(5.6), X(16.55), Z(6.1))
            .L(X(16.4), Z(8.7)), 0.62); // 頂桁迴右脅
        線(p => p.M(X(7.7), Z(7.1)).L(X(16.2), Z(6.85)), 0.62); // 中桁
        線(p => p.M(X(9.0), Z(5.5)).L(X(8.95), Z(8.6))); // 左室內豎
        線(p => p.M(X(13.8), Z(5.35)).L(X(13.75), Z(8.8))); // 右室內豎
        // 左小箱（圓角迴底）
        線(p => p.M(X(7.7), Z(8.65)).L(X(11.2), Z(8.5)).L(X(11.25), Z(10.05))
            .L(X(7.9), Z(10.2)), 0.58);
        出(p => p.M(X(7.7), Z(8.7)).L(X(7.7), Z(10.9))
            .C(X(7.7), Z(11.5), X(8.2), Z(11.7), X(9.0), Z(11.65))
            .L(X(11.0), Z(11.55)), 0.58);
        // 右巳箱
        線(p => p.M(X(12.7), Z(8.9)).L(X(16.85), Z(8.7)), 0.58);
        線(p => p.M(X(12.7), Z(8.95)).L(X(12.65), Z(11.85)));
        出(p => p.M(X(16.85), Z(8.75)).L(X(16.8), Z(11.6))
            .C(X(16.75), Z(11.75), X(16.6), Z(11.8), X(16.4), Z(11.8))
            .L(X(12.7), Z(11.9)), 0.58);
        // 曰箱圓迴（三桁圓角連書）
        出(p => p.M(X(7.1), Z(13.3)).L(X(7.15), Z(17.6))
            .C(X(7.2), Z(18.2), X(7.7), Z(18.4), X(8.6), Z(18.35))
            .L(X(16.5), Z(18.1)), 0.62); // 左脅迴底桁
        出(p => p.M(X(7.2), Z(13.9)).L(X(15.9), Z(13.6))
            .C(X(16.4), Z(13.6), X(16.5), Z(14.0), X(16.45), Z(14.5))
            .L(X(16.4), Z(15.6)), 0.62); // 頂桁迴右
        線(p => p.M(X(7.2), Z(16.0)).L(X(16.4), Z(15.7)), 0.62); // 中桁
        // 右懸針長垂
        出(p => p.M(X(16.6), Z(19.9)).C(X(16.4), Z(24.0), X(16.5), Z(28.0), X(16.3), Z(32.3)), 0.68);
    });
};
